"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[96210],{74584(e,t,i){i.r(t),i.d(t,{assets:()=>c,contentTitle:()=>r,default:()=>h,frontMatter:()=>o,metadata:()=>n,toc:()=>d});let n=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 27 Separate Financial Statements/investment-in-a-subsidiary-accounted-58c9158598","title":"Investment in a subsidiary accounted for at cost: Step acquisition (IAS 27)","description":"January 2019","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 27 Separate Financial Statements/Investment in a subsidiary accounted for at cost  Step acquisition (IAS 27).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 27 Separate Financial Statements","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-27-separate-financial-statements-ad3bcbac8c/investment-in-a-subsidiary-accounted-58c9158598","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-27-separate-financial-statements-ad3bcbac8c/investment-in-a-subsidiary-accounted-58c9158598","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"investment-in-a-subsidiary-accounted-58c9158598","title":"Investment in a subsidiary accounted for at cost: Step acquisition (IAS 27)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-27-separate-financial-statements-ad3bcbac8c/investment-in-a-subsidiary-accounted-58c9158598","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Over Time Transfer of Constructed Good (IAS 23)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-23-borrowing-costs-c7e76e1ff5/over-time-transfer-of-constructed-go-aa70bd8985"},"next":{"title":"Investment in a subsidiary accounted for at cost: Partial disposal(IAS 27)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-27-separate-financial-statements-ad3bcbac8c/investment-in-a-subsidiary-accounted-a645a26507"}}');var a=i(74848),s=i(28453);let o={id:"investment-in-a-subsidiary-accounted-58c9158598",title:"Investment in a subsidiary accounted for at cost: Step acquisition (IAS 27)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-27-separate-financial-statements-ad3bcbac8c/investment-in-a-subsidiary-accounted-58c9158598",sidebar_position:1},r="Investment in a subsidiary accounted for at cost: Step acquisition (IAS 27)",c={},d=[{value:"Question A",id:"question-a",level:2},{value:"Question B",id:"question-b",level:2}];function l(e){let t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"investment-in-a-subsidiary-accounted-for-at-cost-step-acquisition-ias-27",children:"Investment in a subsidiary accounted for at cost: Step acquisition (IAS 27)"})}),"\n",(0,a.jsx)(t.p,{children:"January 2019"}),"\n",(0,a.jsx)(t.p,{children:"The Committee received a request about how an entity applies the requirements in IAS 27 to a fact pattern involving an investment in a subsidiary."}),"\n",(0,a.jsx)(t.p,{children:"In the fact pattern described in the request, the entity preparing separate financial statements:"}),"\n",(0,a.jsx)(t.p,{children:"\u2022 elects to account for its investments in subsidiaries at cost applying paragraph 10 of IAS 27.\n\u2022 holds an initial investment in another entity (investee). The investment is an investment in an equity instrument as defined in paragraph 11 of IAS 32 Financial Instruments: Presentation. The investee is not an associate, joint venture or subsidiary of the entity and, accordingly, the entity applies IFRS 9 Financial Instruments in accounting for its initial investment (initial interest).\n\u2022 subsequently acquires an additional interest in the investee (additional interest), which results in the entity obtaining control of the investee\u2013\u2013ie the investee becomes a subsidiary of the entity."}),"\n",(0,a.jsx)(t.p,{children:"The request asked:"}),"\n",(0,a.jsx)(t.p,{children:"a. whether the entity determines the cost of its investment in the subsidiary as the sum of:"}),"\n",(0,a.jsx)(t.p,{children:"i. the fair value of the initial interest at the date of obtaining control of the subsidiary, plus any consideration paid for the additional interest (fair value as deemed cost approach); or\ni. the consideration paid for the initial interest (original consideration), plus any consideration paid for the additional interest (accumulated cost\napproach) (Question A)."}),"\n",(0,a.jsx)(t.p,{children:"b. how the entity accounts for any difference between the fair value of the initial interest at the date of obtaining control of the subsidiary and its original consideration when applying the accumulated cost approach (Question B)."}),"\n",(0,a.jsx)(t.h2,{id:"question-a",children:"Question A"}),"\n",(0,a.jsx)(t.p,{children:"IAS 27 does not define \u2018cost\u2019, nor does it specify how an entity determines the cost of an investment acquired in stages. The Committee noted that cost is defined in other IFRS Standards (for example, paragraph 6 of IAS 16 Property Plant and Equipment, paragraph 8 of IAS 38 Intangible Assets and paragraph 5 of IAS 40 Investment Property). The Committee observed that the two approaches outlined in the request arise from different views of whether the step acquisition transaction involves:"}),"\n",(0,a.jsx)(t.p,{children:"a. the entity exchanging its initial interest (plus consideration paid for the additional interest) for a controlling interest in the investee, or\nb. purchasing the additional interest while retaining the initial interest."}),"\n",(0,a.jsx)(t.p,{children:"Based on its analysis, the Committee concluded that a reasonable reading of the requirements in IFRS Standards could result in the application of either one of the two approaches outlined in this agenda decision (ie fair value as deemed cost approach or accumulated cost approach)."}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that an entity would apply its reading of the requirements consistently to step acquisition transactions. An entity would also disclose the selected approach applying paragraphs 117\u2013124 of IAS 1 Presentation of Financial Statements if that disclosure would assist users of financial statements in understanding how step acquisition transactions are reflected in reporting financial performance and financial position."}),"\n",(0,a.jsx)(t.h2,{id:"question-b",children:"Question B"}),"\n",(0,a.jsx)(t.p,{children:"In applying the accumulated cost approach, any difference between the fair value of the initial interest at the date of obtaining control of the subsidiary and its original consideration meets the definitions of income or expenses in the Conceptual Framework for Financial Reporting. Accordingly, the Committee concluded that, applying paragraph 88 of IAS 1, the entity recognises this difference in profit or loss, regardless of whether, before obtaining control, the entity had presented subsequent changes in fair value of the initial interest in profit or loss or other comprehensive income."}),"\n",(0,a.jsx)(t.p,{children:"For Question A, the Committee considered whether to develop a narrow-scope amendment to address how an entity determines the cost of an investment acquired in stages. The Committee observed that:"}),"\n",(0,a.jsx)(t.p,{children:"a. it did not have evidence to assess whether the application of the two acceptable approaches to determining cost, outlined in this agenda decision, would have a material effect on those affected.\nb. the matter could not be resolved without also considering the requirements in paragraph 10 of IAS 28 to initially measure an investment in an associate or joint venture at cost. The Committee did not obtain information to suggest that the Board should reconsider this aspect of IAS 28 at this stage, rather than as part of its wider consideration of IAS 28 within its research project on the Equity Method."}),"\n",(0,a.jsx)(t.p,{children:"On balance, the Committee decided not to undertake standard-setting to address Question A."}),"\n",(0,a.jsx)(t.p,{children:"For Question B, the Committee concluded that the principles and requirements in IFRS Standards provide an adequate basis for an entity to determine its accounting."}),"\n",(0,a.jsx)(t.p,{children:"Consequently, the Committee decided not to add these matters to its standard-setting agenda."})]})}function h(e={}){let{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(l,{...e})}):l(e)}},28453(e,t,i){i.d(t,{R:()=>o,x:()=>r});var n=i(96540);let a={},s=n.createContext(a);function o(e){let t=n.useContext(s);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:o(e.components),n.createElement(s.Provider,{value:t},e.children)}}}]);